create table limo_car_type_prices (
    price_id       number not null enable,
    car_type_id    varchar2(240 byte),
    price_per_trip number(10, 2),
    currency       varchar2(10 byte),
    exchange_rate  number(10, 4),
    amount_in_egp  number,
    is_special     varchar2(1 byte),
    created        timestamp(6) with time zone,
    created_by     varchar2(100 byte),
    updated        timestamp(6) with time zone,
    updated_by     varchar2(100 byte),
    notes          varchar2(500 byte),
    start_date     timestamp(6) with time zone,
    end_date       timestamp(6) with time zone
);


